                                setSiLingConfig({ source: '自定义', customTable: JSON.parse(JSON.stringify(initialCustom)) });
                            }}
                            className={`px-3 py-2 text-xs font-bold rounded-lg border transition-all ${
                                siLingConfig.source === '自定义' 
                                ? 'bg-[#8B0000] text-white border-[#8B0000]' 
                                : 'bg-white text-[#5c4033] border-[#d6cda4]'
                            }`}
                        >
                            自定义排法
                        </button>
                    </div>
                </section>

                {siLingConfig.source === '自定义' && siLingConfig.customTable && (
                    <section className="animate-fadeIn">
                        <label className="text-xs text-[#a89f91] font-bold uppercase tracking-wider block mb-3">编辑分日规则 (12月令)</label>
                        <div className="space-y-4">
                            {ZHI.map(branch => (
                                <div key={branch} className="bg-white p-3 rounded-lg border border-[#ebe5ce]">
                                    <div className="text-sm font-bold text-[#8B0000] mb-2 border-b pb-1">{branch}月</div>
                                    <div className="space-y-2">
                                        {(siLingConfig.customTable![branch] || []).map((rule, idx) => (
                                            <div key={idx} className="flex gap-2 items-center">
                                                <select 
                                                    value={rule.gan}
                                                    onChange={(e) => {
                                                        const newTable = { ...siLingConfig.customTable! };
                                                        newTable[branch][idx].gan = e.target.value;
                                                        setSiLingConfig({ ...siLingConfig, customTable: newTable });
                                                    }}
                                                    className="bg-[#fff8ea] border border-[#d6cda4] rounded px-2 py-1 text-sm outline-none"
                                                >
                                                    {GAN.map(g => <option key={g} value={g}>{g}</option>)}
                                                </select>
                                                <input 
                                                    type="number"
                                                    value={rule.days}
                                                    onChange={(e) => {
                                                        const newTable = { ...siLingConfig.customTable! };
                                                        newTable[branch][idx].days = parseInt(e.target.value) || 0;
                                                        setSiLingConfig({ ...siLingConfig, customTable: newTable });
                                                    }}
                                                    className="w-16 bg-[#fff8ea] border border-[#d6cda4] rounded px-2 py-1 text-sm outline-none"
                                                />
                                                <span className="text-xs text-[#a89f91]">天</span>
                                                {idx === (siLingConfig.customTable![branch].length - 1) && (
                                                    <button 
                                                        onClick={() => {
                                                            const newTable = { ...siLingConfig.customTable! };
                                                            newTable[branch].push({ gan: '甲', days: 0 });
