                             </div>
                         ))}

                         {[chart.year, chart.month, chart.day, chart.hour].map((p, i) => (
                             <div key={`hs-${i}`} className="flex flex-col items-center mt-1 space-y-0.5">
                                 {p.hiddenStems.map((hs, idx) => (
                                     <div key={idx} className="flex gap-0.5 items-center text-[15px] leading-none">
                                         <span className={`${ELEMENT_COLORS[hs.element]}`}>{hs.stem}</span>
                                         <span className="text-[#666] scale-90 origin-left">{hs.tenGod}</span>
                                     </div>
                                 ))}
                             </div>
                         ))}

                         {[chart.year, chart.month, chart.day, chart.hour].map((p, i) => (
                             <div key={`ls-${i}`} className="mt-2 text-[15px] text-[#333]">{p.lifeStage}</div>
                         ))}
                    </div>
                </div>
            </div>

            <div className="mt-1 space-y-0.5 text-[15px] leading-snug">
                <div className="flex gap-2">
                    <span className="text-green-700">
                        司令: {chart.renYuanSiLing} 
                        <button 
                            onClick={() => setShowSiLingModal(true)}
                            className="ml-2 text-green-700"
                        >
                            [设置]
                        </button>
                    </span>
                </div>
            </div>

            <div className="mt-1 text-[15px]">
                <div className="text-[#333]">{chart.startLuckText} <span className="text-green-600">[设置]</span></div>
                <div className="text-[#333]">即每逢乙年清明后第7日交脱大运, 当前: <span className="text-[#8B0000] font-bold">{currentDaYunStr}</span></div>
            </div>

            <div 
                ref={chartScrollRef}
                className="mt-1 overflow-x-hidden whitespace-nowrap"
            >
                <div className="min-w-max">
                     <div className="flex">
                         <div className="flex flex-col w-12 items-center shrink-0">
                             <div className="h-4"></div>
                             <div className="h-4"></div>
                             {(() => {
                                 const isCurrentYunQian = chart.yunQian.some(y => y.year === currentYear);
                                 const highlightColor = 'text-[#8B0000]'; 

                                 return (
                                     <>
                                        <div 
                                            className="w-full flex flex-col items-center cursor-grab active:cursor-grabbing"
                                            onTouchStart={handleDaYunTouchStart}
                                            onTouchMove={handleDaYunTouchMove}
                                            onTouchEnd={handleDaYunTouchEnd}
                                        >
                                            <div className={`h-8 flex items-center justify-center font-bold text-lg ${isCurrentYunQian ? highlightColor : 'text-[#1c1917]'}`}>运前</div>
                                            <div className="h-4 text-[15px] text-[#333]">1</div>
                                            <div className="h-4 text-[15px] text-[#333]">{chart.yunQian[0]?.year}</div>
                                        </div>

                                        <div className="mt-2 w-full flex flex-col items-center gap-1 select-none">
                                            {chart.yunQian.map((yn, idx) => {
                                                const isCurrent = yn.year === currentYear;
                                                const textColor = isCurrentYunQian 
                                                    ? (isCurrent ? `${highlightColor} font-bold` : highlightColor) 
                                                    : 'text-[#333]';

                                                return (
                                                    <div key={idx} className={`flex items-center justify-center h-[18px] w-full ${textColor}`}>
                                                        <span className="text-[15px] tracking-widest">{yn.ganZhi}</span>
                                                    </div>
                                                );
                                            })}
                                        </div>
                                     </>
                                 );
                             })()}
                         </div>

                         {chart.daYun.map((yun, idx) => {
                             const nextYun = chart.daYun[idx + 1];
                             const isCurrentDaYun = currentYear >= yun.startYear && (!nextYun || currentYear < nextYun.startYear);
                             const highlightColor = 'text-[#8B0000]'; 

                             return (
                             <div key={yun.index} className="flex flex-col w-12 items-center shrink-0">
                                 <div 
                                    className="w-full flex flex-col items-center cursor-grab active:cursor-grabbing"
                                    onTouchStart={handleDaYunTouchStart}
                                    onTouchMove={handleDaYunTouchMove}
                                    onTouchEnd={handleDaYunTouchEnd}
                                 >
                                    <div className="h-4 text-[15px] text-[#333] scale-90 whitespace-nowrap">{yun.naYin}</div>
                                    <div className="h-4 text-[15px] text-[#333]">{yun.stemTenGod}</div>

                                    <div className={`h-8 flex items-center justify-center ${isCurrentDaYun ? highlightColor : 'text-[#1c1917]'} font-bold`}>
                                        <span className="text-lg tracking-wide">{yun.ganZhi}</span> 
                                    </div>

                                    <div className="h-4 text-[15px] text-[#333]">{yun.startAge}</div>
                                    <div className="h-4 text-[15px] text-[#333]">{yun.startYear}</div>
                                 </div>

                                 <div className="mt-2 w-full flex flex-col items-center gap-1 select-none">
                                     {yun.liuNian.map((ln, lnIdx) => {
                                         const isCurrentLiuNian = ln.year === currentYear;
                                         const baseColor = isCurrentDaYun ? highlightColor : 'text-[#333]';
                                         const textColor = isCurrentLiuNian ? `${highlightColor} font-bold` : baseColor;

                                         return (
                                            <div key={lnIdx} className={`flex items-center justify-center h-[18px] w-full ${textColor}`}>
                                                <span className="text-[15px] tracking-widest">{ln.ganZhi}</span>
                                            </div>
                                         );
                                     })}
                                 </div>
                             </div>
                         )})}
                     </div>
                </div>
            </div>

            <div className="mt-8 mb-6 px-2">
                <div className="bg-white/60 border border-[#d6cda4] rounded-lg p-3 shadow-sm">
                    <div className="flex justify-between items-center mb-2 pb-2 border-b border-[#e5e0d0]">
                        <h3 className="font-bold text-[#8B0000] text-[17px] flex items-center gap-2">
                            <Edit3 size={18}/> 命理师批注
                        </h3>
                        <div className="flex gap-2">
                            <button 
                                onClick={handleAIAnalyze} 
                                className="text-[10px] px-2 py-1 bg-[#eaddcf] text-[#5c4033] rounded hover:bg-[#d6cda4] transition-colors"
                                disabled={isAnalyzing}
                            >
                                {isAnalyzing ? "AI推算中..." : "AI辅助批注"}
                            </button>
                            <button 
                                onClick={handleSaveRecord} 
                                className="text-[10px] px-3 py-1 bg-[#8B0000] text-white rounded shadow-sm hover:bg-[#7a0000] transition-colors"
                            >
                                保存
                            </button>
                        </div>
                    </div>
                    <textarea
                        ref={textareaRef}
                        className="w-full min-h-[120px] bg-transparent outline-none resize-none text-[17px] font-sans leading-relaxed text-[#450a0a] placeholder-[#a89f91] overflow-hidden"
                        placeholder="在此输入命理分析..."
                        value={noteDraft}
                        onChange={(e) => setNoteDraft(e.target.value)}
                    />
                </div>
            </div>

        </div>
      </div>
    );
  };

  return (
    <>
      <HistoryDrawer 
        isOpen={historyOpen} 
        onClose={() => setHistoryOpen(false)} 
        records={records}
        activeRecordId={currentRecord?.id}
        onSelect={loadRecord}
        onEdit={handleEditRecord}
        onDelete={deleteRecord}
        onImport={handleRestoreClick}
        onBackup={handleBackup}
        onUpdateGroup={handleRenameGroup}
        onDeleteGroup={handleDeleteGroup}
      />

      {showSettings && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/40 backdrop-blur-sm p-4 animate-fadeIn">
            <div className="bg-[#fffcf5] rounded-xl w-full max-w-xs border border-[#d6cda4] shadow-2xl relative overflow-hidden">
                <div className="bg-[#fff8ea] p-4 border-b border-[#e5e0d0] flex justify-between items-center">
                    <h3 className="text-lg font-bold text-[#8B0000] flex items-center gap-2">
                        <Settings size={18} /> 设置与数据
                    </h3>
                    <button onClick={() => setShowSettings(false)} className="text-[#a89f91] hover:text-[#5c4033]">
                        <X size={20}/>
                    </button>
                </div>

                <div className="p-5 space-y-4">
                    <div className="space-y-3">
                        <label className="text-xs text-[#a89f91] font-bold uppercase tracking-wider block mb-2">数据管理</label>
                        <button 
                            type="button"
                            onClick={handleBackup}
                            className="w-full flex items-center justify-between bg-white border border-[#d6cda4] p-3 rounded-lg text-[#450a0a] hover:border-[#8B0000] hover:bg-[#fff8ea] transition-all group"
                        >
                            <span className="flex items-center gap-3 font-bold text-sm">
                                <span className="bg-[#eaddcf] p-1.5 rounded text-[#5c4033] group-hover:text-[#8B0000] transition-colors"><Download size={16}/></span>
                                备份所有数据
                            </span>
                            <ChevronRight size={16} className="text-[#d6cda4] group-hover:text-[#8B0000]"/>
                        </button>

                        <button 
                            type="button"
                            onClick={handleRestoreClick}
                            className="w-full flex items-center justify-between bg-white border border-[#d6cda4] p-3 rounded-lg text-[#450a0a] hover:border-[#8B0000] hover:bg-[#fff8ea] transition-all group"
                        >
                             <span className="flex items-center gap-3 font-bold text-sm">
                                <span className="bg-[#eaddcf] p-1.5 rounded text-[#5c4033] group-hover:text-[#8B0000] transition-colors"><Upload size={16}/></span>
                                恢复数据 (导入)
                            </span>
                            <ChevronRight size={16} className="text-[#d6cda4] group-hover:text-[#8B0000]"/>
                        </button>
                    </div>

                    <div className="bg-[#fdfbf6] p-3 rounded border border-[#f0ebda] text-[11px] text-[#8c7b75] leading-relaxed">
                        <p className="flex items-start gap-1">
                            <FileText size={12} className="mt-0.5 shrink-0"/>
                            更新 App 前，请先点击“备份”将数据保存到手机“文件”中。如果无反应，将自动复制到剪贴板，请粘贴保存。更新完成后，点击“恢复”导入。
                        </p>
                    </div>
                </div>
            </div>
        </div>
      )}

      {showSiLingModal && renderSiLingModal()}

      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        className="hidden" 
        accept=".json,application/json"
      />

      {view === 'form' ? renderForm() : renderChart()}
    </>
  );
}

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
// FIX: Alias the imported `Record` to `BaZiRecord` to avoid conflict with TypeScript's built-in `Record` utility type.
import { Record as BaZiRecord } from '../types';
import { X, Clock, Trash2, Search, Folder, ChevronRight, Download, Upload, MapPin, Edit3, AlertCircle, SortAsc, ChevronUp, ChevronDown } from 'lucide-react';
import { pinyin } from 'pinyin-pro';
import { GROUP_ORDER_KEY } from '../constants';

interface HistoryDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  records: BaZiRecord[];
  activeRecordId?: string; // New prop to identify the currently viewed record
  onSelect: (record: BaZiRecord) => void;
  onEdit: (record: BaZiRecord) => void; 
  onDelete: (id: string) => void;
  onImport: () => void;
  onBackup: (e: React.MouseEvent) => void;
  onUpdateGroup?: (oldName: string, newName: string) => void;
  onDeleteGroup?: (groupName: string) => void;
}

const AZ = "ABCDEFGHIJKLMNOPQRSTUVWXYZ#".split("");

export const HistoryDrawer: React.FC<HistoryDrawerProps> = ({ 
    isOpen, onClose, records, activeRecordId, onSelect, onEdit, onDelete, onImport, onBackup,
    onUpdateGroup, onDeleteGroup
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedGroup, setSelectedGroup] = useState<string>('全部');
  const [sortMode, setSortMode] = useState<'time' | 'alpha'>('time');

  // Group Management State
  const [editingGroup, setEditingGroup] = useState<{original: string, current: string} | null>(null);
  const [customGroupOrder, setCustomGroupOrder] = useState<string[]>(() => {
    const saved = localStorage.getItem(GROUP_ORDER_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const pressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isLongPressTriggered = useRef(false);

  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const alphaRefs = useRef<{ [key: string]: HTMLDivElement | null }>({});
  const activeRecordRef = useRef<HTMLDivElement | null>(null);

  // Sync custom order when groups change
  const currentGroupsList = useMemo(() => {
    const uniqueGroups = Array.from(new Set(records.map(r => r.group || '默认分组')));

    // Merge with existing custom order
    let newOrder = [...customGroupOrder];
    // Add new groups found in records
    uniqueGroups.forEach(g => {
      if (!newOrder.includes(g)) newOrder.push(g);
    });
    // Remove groups that no longer exist
    newOrder = newOrder.filter(g => uniqueGroups.includes(g));

    return newOrder;
  }, [records, customGroupOrder]);

  const finalSortedGroups = useMemo(() => ['全部', ...currentGroupsList], [currentGroupsList]);

  // Save order whenever it changes
  useEffect(() => {
    localStorage.setItem(GROUP_ORDER_KEY, JSON.stringify(currentGroupsList));
  }, [currentGroupsList]);

  // Reset to time sort every time drawer opens and scroll to active
  useEffect(() => {
      if (isOpen) {
          setSortMode('time');
          setSearchTerm('');
          setTimeout(() => {
              if (activeRecordRef.current) {
                  activeRecordRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
              }
          }, 100);
      }
  }, [isOpen]);

  // Main Filtered & Sorted Logic
  const processedData = useMemo(() => {
    const baseList = records.filter(rec => {
      const rawTerm = searchTerm.trim().toLowerCase();
      const recGroup = rec.group || '默认分组';

      let matchesSearch = true;
      if (rawTerm) {
          const terms = rawTerm.split(/\s+/);
          const chartStr = `${rec.chart.year.stem}${rec.chart.year.branch}${rec.chart.month.stem}${rec.chart.month.branch}${rec.chart.day.stem}${rec.chart.day.branch}${rec.chart.hour.stem}${rec.chart.hour.branch}`;
          const fullSearchText = `${rec.name.toLowerCase()} ${recGroup.toLowerCase()} ${chartStr}`;
          matchesSearch = terms.every(t => fullSearchText.includes(t));
      }

      const matchesGroup = selectedGroup === '全部' || recGroup === selectedGroup;
      return matchesSearch && matchesGroup;
    });

    if (sortMode === 'time') {
        return baseList.sort((a, b) => b.createdAt - a.createdAt);
    } else {
        const alphaGrouped: { [key: string]: BaZiRecord[] } = {};

        baseList.forEach(rec => {
            const firstChar = rec.name.trim().charAt(0);
            let letter = '#';
            if (firstChar) {
                const py = pinyin(firstChar, { pattern: 'initial', toneType: 'none' });
                if (py && /^[a-zA-Z]/.test(py)) {
                    letter = py.toUpperCase();
                }
            }
            if (!alphaGrouped[letter]) alphaGrouped[letter] = [];
            alphaGrouped[letter].push(rec);
        });

        Object.keys(alphaGrouped).forEach(key => {
            alphaGrouped[key].sort((a, b) => a.name.localeCompare(b.name, 'zh-Hans-CN'));
        });

        return alphaGrouped;
    }
  }, [records, searchTerm, selectedGroup, sortMode]);

  const handleIndexScroll = (letter: string) => {
      if (sortMode !== 'alpha') setSortMode('alpha');
      const target = alphaRefs.current[letter];
      if (target) {
          target.scrollIntoView({ behavior: 'auto', block: 'start' });
          if (navigator.vibrate) navigator.vibrate(5);
      }
  };

  const onIndexTouchMove = (e: React.TouchEvent) => {
      const touch = e.touches[0];
      const target = document.elementFromPoint(touch.clientX, touch.clientY);
      const letter = target?.getAttribute('data-letter');
      if (letter) {
          handleIndexScroll(letter);
      }
  };

  const handleTouchStart = (group: string) => {
      if (group === '全部') return;
      isLongPressTriggered.current = false;
      if (pressTimer.current) clearTimeout(pressTimer.current);
      pressTimer.current = setTimeout(() => {
          isLongPressTriggered.current = true;
          setEditingGroup({ original: group, current: group });
          if (navigator.vibrate) navigator.vibrate(50);
      }, 600);
  };

  const handleTouchEnd = (group: string) => {
      if (pressTimer.current) clearTimeout(pressTimer.current);
      if (!isLongPressTriggered.current) {
          setSelectedGroup(group);
      }
  };

  const saveGroupEdit = () => {
      if (!editingGroup || !onUpdateGroup) return;
      if (editingGroup.current.trim() && editingGroup.current !== editingGroup.original) {
          onUpdateGroup(editingGroup.original, editingGroup.current.trim());
          // Update custom order too
          const newOrder = customGroupOrder.map(g => g === editingGroup.original ? editingGroup.current.trim() : g);
          setCustomGroupOrder(newOrder);
      }
      setEditingGroup(null);
  };

  const deleteGroupAction = () => {
      if (!editingGroup || !onDeleteGroup) return;
      if (confirm(`确定要删除分组 "${editingGroup.original}" 吗？\n组内案例将移至默认分组。`)) {
          onDeleteGroup(editingGroup.original);
          setEditingGroup(null);
          setSelectedGroup('全部');
      }
  };

  const moveGroup = (direction: 'up' | 'down') => {
    if (!editingGroup) return;
    const index = customGroupOrder.indexOf(editingGroup.original);
    if (index === -1) return;

    const newOrder = [...customGroupOrder];
    if (direction === 'up' && index > 0) {
      [newOrder[index], newOrder[index - 1]] = [newOrder[index - 1], newOrder[index]];
    } else if (direction === 'down' && index < newOrder.length - 1) {
      [newOrder[index], newOrder[index + 1]] = [newOrder[index + 1], newOrder[index]];
    }
    setCustomGroupOrder(newOrder);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[60] flex justify-end">
      <div className="absolute inset-0 bg-black/30 backdrop-blur-sm transition-opacity" onClick={onClose} />

      <div className="relative w-[85%] max-w-sm h-full bg-[#fffcf5] shadow-2xl flex flex-col font-sans animate-slideLeft border-l border-[#d6cda4] pt-[env(safe-area-inset-top)]">

        <div className="p-4 border-b border-[#d6cda4] flex justify-between items-center bg-[#fff8ea] shrink-0">
          <div className="flex flex-col">
              <h2 className="text-lg font-bold text-[#8B0000] font-serif flex items-center gap-2">
                <Clock size={18} /> 历史档案
              </h2>
              <div className="flex gap-4 mt-1">
                  <button 
                    onClick={() => setSortMode('time')}
                    className={`text-[10px] font-bold pb-0.5 border-b-2 transition-all ${sortMode === 'time' ? 'text-[#8B0000] border-[#8B0000]' : 'text-[#a89f91] border-transparent'}`}
                  >
                    按时间排序
                  </button>
                  <button 
                    onClick={() => setSortMode('alpha')}
                    className={`text-[10px] font-bold pb-0.5 border-b-2 transition-all ${sortMode === 'alpha' ? 'text-[#8B0000] border-[#8B0000]' : 'text-[#a89f91] border-transparent'}`}
                  >
                    按名字排序
                  </button>
              </div>
          </div>
          <button onClick={onClose} className="text-[#8B0000]/50 hover:text-[#8B0000] transition-colors p-1 rounded-full hover:bg-[#8B0000]/10">
            <X size={24} />
          </button>
        </div>

        <div className="p-3 bg-[#fffcf5] border-b border-[#ebe5ce] space-y-3 shrink-0">
            <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-[#a89f91]" size={14} />
                <input 
                    type="text" 
                    placeholder="搜姓名 或八字(如:甲子 丙寅)..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full bg-white border border-[#d6cda4] rounded-full py-2 pl-9 pr-4 text-sm text-[#450a0a] focus:border-[#8B0000] outline-none placeholder-[#d6cda4]"
                />
            </div>

            <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                {finalSortedGroups.map(group => (
                    <button
                        key={group}
                        onTouchStart={() => handleTouchStart(group)}
                        onTouchEnd={() => handleTouchEnd(group)}
                        onMouseDown={() => handleTouchStart(group)}
                        onMouseUp={() => handleTouchEnd(group)}
                        className={`whitespace-nowrap px-3 py-1 rounded-full text-xs font-bold border shadow-sm select-none ${
                            selectedGroup === group 
                            ? 'bg-[#8B0000] text-[#fff8ea] border-[#8B0000]' 
                            : 'bg-white text-[#5c4033] border-[#d6cda4]'
                        }`}
                    >
                        {group}
                    </button>
                ))}
            </div>
        </div>

        <div className="flex flex-1 overflow-hidden relative">
            <div 
                ref={scrollContainerRef}
                className="flex-1 overflow-y-auto p-3 space-y-3 bg-[#fdfbf6] overscroll-contain pr-6"
            >
              {sortMode === 'time' ? (
                (processedData as BaZiRecord[]).length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-40 text-[#a89f91] space-y-2">
                        <Search size={32} opacity={0.2} />
                        <span className="text-xs">暂无匹配记录</span>
                    </div>
                ) : (
                    (processedData as BaZiRecord[]).map(rec => (
                        <div key={rec.id} ref={rec.id === activeRecordId ? activeRecordRef : null}>
                            {renderRecordCard(rec, onSelect, onEdit, onDelete, onClose, rec.id === activeRecordId)}
                        </div>
                    ))
                )
              ) : (
                Object.keys(processedData).sort().map(letter => (
                    <div key={letter} ref={el => { alphaRefs.current[letter] = el; }} className="space-y-2">
                        <div className="sticky top-0 z-10 bg-[#fdfbf6]/90 backdrop-blur-sm py-1">
                            <span className="bg-[#8B0000] text-white text-[10px] px-2 py-0.5 rounded-full font-bold">{letter}</span>
                        </div>
                        {(processedData as any)[letter].map((rec: BaZiRecord) => (
                            <div key={rec.id} ref={rec.id === activeRecordId ? activeRecordRef : null}>
                                {renderRecordCard(rec, onSelect, onEdit, onDelete, onClose, rec.id === activeRecordId)}
                            </div>
                        ))}
                    </div>
                ))
              )}
            </div>

            <div 
                className="absolute right-0 top-0 bottom-0 w-6 flex flex-col items-center justify-center bg-transparent z-20 select-none"
                onTouchMove={onIndexTouchMove}
            >
                {AZ.map(letter => (
                    <div 
                        key={letter}
                        data-letter={letter}
                        onClick={() => handleIndexScroll(letter)}
                        className="text-[8px] font-bold text-[#8B0000]/60 hover:text-[#8B0000] py-0.5 w-full text-center transition-colors cursor-pointer active:scale-125"
                    >
                        {letter}
                    </div>
                ))}
            </div>
        </div>

        <div className="p-3 border-t border-[#d6cda4] bg-[#fffcf5] flex gap-2 shrink-0">
            <button onClick={onBackup} className="flex-1 flex items-center justify-center gap-1 bg-[#eaddcf] text-[#5c4033] py-2 rounded text-xs font-bold transition-colors">
                <Download size={14} /> 备份数据
            </button>
            <button onClick={onImport} className="flex-1 flex items-center justify-center gap-1 bg-[#8B0000] text-white py-2 rounded text-xs font-bold transition-colors">
                <Upload size={14} /> 恢复数据
            </button>
        </div>

        <div className="pb-4 pt-1 text-center text-[10px] text-[#a89f91] bg-[#fffcf5] shrink-0">
            共 {records.length} 条档案 · 长按分组名进入管理模式
        </div>

        {editingGroup && (
            <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-[2px] p-6 animate-fadeIn">
                <div className="bg-white rounded-lg shadow-xl w-full border border-[#d6cda4] overflow-hidden">
                    <div className="bg-[#fff8ea] p-3 border-b border-[#eaddcf] flex justify-between items-center">
                        <h3 className="text-[#8B0000] font-bold text-sm">管理分组: {editingGroup.original}</h3>
                        <button onClick={() => setEditingGroup(null)}><X size={18} className="text-[#a89f91]"/></button>
                    </div>
