                                >
                                  <ChevronUp size={14}/> 前移
                                </button>
                                <button 
                                  onClick={() => moveGroup('down')} 
                                  className="flex-1 flex items-center justify-center gap-1 py-2 text-xs font-bold bg-stone-100 rounded text-[#450a0a] active:bg-stone-200"
                                >
                                  <ChevronDown size={14}/> 后移
                                </button>
                            </div>

                            <div className="flex gap-2">
                                <button 
                                  onClick={deleteGroupAction} 
                                  className="flex-1 py-2 text-xs font-bold text-red-600 bg-red-50 rounded"
                                  disabled={editingGroup.original === '默认分组'}
                                >
                                  删除分组
                                </button>
                                <button 
                                  onClick={saveGroupEdit} 
                                  className="flex-[2] py-2 text-xs font-bold text-white bg-[#8B0000] rounded shadow-sm"
                                >
                                  保存并应用
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

